import toast from "react-hot-toast";
import { useAppStore } from "../store/appStore";

export default function SettingsPage() {
  const { user, subscription, settings, updateSettings, openWebsite, logout } = useAppStore();

  const toggle = async (key) => {
    await updateSettings({ [key]: !settings[key] });
    toast.success("Settings updated");
  };

  return (
    <div className="grid gap-4 md:grid-cols-2">
      <div className="card">
        <h3 className="mb-3 text-lg font-semibold">Account</h3>
        <p className="text-sm">Email: {user?.email}</p>
        <p className="text-sm">Name: {user?.firstName} {user?.lastName}</p>
        <button className="mt-3 text-sm text-brand-700 hover:underline" onClick={() => openWebsite("/account/change-password")}>Change Password</button>
      </div>

      <div className="card">
        <h3 className="mb-3 text-lg font-semibold">Subscription</h3>
        <p className="text-sm">Plan: {subscription?.planType || "-"}</p>
        <p className="text-sm">Credits/Month: {subscription?.creditsPerMonth || "-"}</p>
        <p className="text-sm">Next Billing: {subscription?.nextBillingDate ? new Date(subscription.nextBillingDate).toLocaleDateString() : "-"}</p>
        <button className="mt-3 text-sm text-brand-700 hover:underline" onClick={() => openWebsite("/billing")}>Manage at emailnphonelist.com</button>
      </div>

      <div className="card md:col-span-2">
        <h3 className="mb-3 text-lg font-semibold">App Settings</h3>
        <div className="space-y-2">
          <label className="flex items-center gap-2 text-sm">
            <input type="checkbox" checked={settings.autoUpdate} onChange={() => toggle("autoUpdate")} />
            Auto-check for updates
          </label>
          <label className="flex items-center gap-2 text-sm">
            <input type="checkbox" checked={settings.saveHistory} onChange={() => toggle("saveHistory")} />
            Save validation history
          </label>
        </div>
        <button className="btn-outline mt-4" onClick={logout}>Logout</button>
      </div>
    </div>
  );
}
